def test_primary_holder_executes_transaction(api_client, joint_account_primary):
    payload = {
        "amount": 100.00,
        "type": "transfer",
        "recipient_id": "ACC-002"
    }
    resp = api_client.post(
        f"/accounts/{joint_account_primary['id']}/joint",
        json=payload,
        headers={"Authorization": f"Bearer {joint_account_primary['token']}"}
    )
    assert resp.status_code == 200
    data = resp.json()
    assert data["status"] == "applied"
    assert "transaction_id" in data
    assert data["new_balance"] == joint_account_primary["balance"] - 100.00

def test_secondary_holder_ownership_modification_forbidden(api_client, joint_account_secondary):
    payload = {
        "amount": 50.00,
        "type": "transfer",
        "ownership_change": True,
        "new_owner": "CUST-999"
    }
    resp = api_client.post(
        f"/accounts/{joint_account_secondary['id']}/joint",
        json=payload,
        headers={"Authorization": f"Bearer {joint_account_secondary['token']}"}
    )
    assert resp.status_code == 403
    error = resp.json()
    assert error["error_code"] == "OWNERSHIP_MODIFICATION_DENIED"
    assert error["message"] == "Secondary holder cannot modify ownership"

def test_secondary_holder_zero_amount_transaction_rejected(api_client, joint_account_secondary):
    payload = {
        "amount": 0.00,
        "type": "transfer",
        "recipient_id": "ACC-003"
    }
    resp = api_client.post(
        f"/accounts/{joint_account_secondary['id']}/joint",
        json=payload,
        headers={"Authorization": f"Bearer {joint_account_secondary['token']}"}
    )
    assert resp.status_code == 400
    error = resp.json()
    assert error["error_code"] == "INVALID_TRANSACTION_AMOUNT"
    assert "must be greater than 0" in error["message"]

def test_secondary_holder_normal_transaction_allowed(api_client, joint_account_secondary):
    payload = {
        "amount": 50.00,
        "type": "transfer",
        "recipient_id": "ACC-004"
    }
    resp = api_client.post(
        f"/accounts/{joint_account_secondary['id']}/joint",
        json=payload,
        headers={"Authorization": f"Bearer {joint_account_secondary['token']}"}
    )
    assert resp.status_code == 200
    data = resp.json()
    assert data["status"] == "applied"
    assert data["actor"] == "SECONDARY"
    assert data["ownership_modified"] is False

